import assert from 'node:assert/strict'
import { describe, it } from 'node:test'
import { geo, geoFromHeaders, isInRegion, geoDistance } from './geo'

describe('geo()', () => {
  it('extracts fields from Vercel headers', () => {
    const headers = new Headers({
      'x-vercel-ip-city': 'San Francisco',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'CA',
      'x-vercel-ip-latitude': '37.7749',
      'x-vercel-ip-longitude': '-122.4194',
      'x-vercel-ip-timezone': 'America/Los_Angeles',
    })

    const result = geo({ headers })

    assert.equal(result.city, 'San Francisco')
    assert.equal(result.countryCode, 'US')
    assert.equal(result.country, 'United States')
    assert.equal(result.region, 'CA')
    assert.equal(result.latitude, '37.7749')
    assert.equal(result.longitude, '-122.4194')
    assert.equal(result.timezone, 'America/Los_Angeles')
  })

  it('returns undefined fields when headers are missing', () => {
    const headers = new Headers()
    const result = geo({ headers })

    assert.equal(result.city, undefined)
    assert.equal(result.country, undefined)
    assert.equal(result.countryCode, undefined)
    assert.equal(result.region, undefined)
    assert.equal(result.latitude, undefined)
    assert.equal(result.longitude, undefined)
    assert.equal(result.timezone, undefined)
  })

  it('looks up country name from countryCode', () => {
    const cases: [string, string][] = [
      ['AU', 'Australia'],
      ['BR', 'Brazil'],
      ['CA', 'Canada'],
      ['CN', 'China'],
      ['DE', 'Germany'],
      ['FR', 'France'],
      ['GB', 'United Kingdom'],
      ['IN', 'India'],
      ['JP', 'Japan'],
      ['US', 'United States'],
    ]

    for (const [code, name] of cases) {
      const headers = new Headers({ 'x-vercel-ip-country': code })
      const result = geo({ headers })
      assert.equal(result.country, name, `Expected country for ${code} to be ${name}`)
    }
  })

  it('returns undefined country for unknown countryCode', () => {
    const headers = new Headers({ 'x-vercel-ip-country': 'ZZ' })
    const result = geo({ headers })
    assert.equal(result.countryCode, 'ZZ')
    assert.equal(result.country, undefined)
  })
})

describe('geoFromHeaders()', () => {
  it('falls back to cf-ipcountry for countryCode', () => {
    const headers = new Headers({ 'cf-ipcountry': 'DE' })
    const result = geoFromHeaders(headers)

    assert.equal(result.countryCode, 'DE')
    assert.equal(result.country, 'Germany')
  })

  it('prefers x-vercel-ip-country over cf-ipcountry', () => {
    const headers = new Headers({
      'x-vercel-ip-country': 'FR',
      'cf-ipcountry': 'DE',
    })
    const result = geoFromHeaders(headers)

    assert.equal(result.countryCode, 'FR')
    assert.equal(result.country, 'France')
  })
})

describe('isInRegion()', () => {
  it('returns true when countryCode matches a region in the list', () => {
    assert.equal(isInRegion({ countryCode: 'US' }, ['US', 'CA', 'MX']), true)
  })

  it('returns false when countryCode does not match', () => {
    assert.equal(isInRegion({ countryCode: 'DE' }, ['US', 'CA', 'MX']), false)
  })

  it('is case-insensitive', () => {
    assert.equal(isInRegion({ countryCode: 'us' }, ['US']), true)
    assert.equal(isInRegion({ countryCode: 'US' }, ['us']), true)
  })

  it('returns false when countryCode is undefined', () => {
    assert.equal(isInRegion({}, ['US']), false)
  })

  it('returns false for an empty regions list', () => {
    assert.equal(isInRegion({ countryCode: 'US' }, []), false)
  })
})

describe('geoDistance()', () => {
  it('calculates distance between New York and London within 50 km tolerance', () => {
    // New York: 40.7128° N, 74.0060° W
    // London:   51.5074° N,  0.1278° W
    // Expected: ~5570 km
    const dist = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    assert.ok(
      Math.abs(dist - 5570) < 50,
      `Expected ~5570 km, got ${dist.toFixed(1)} km`
    )
  })

  it('returns 0 for identical coordinates', () => {
    const dist = geoDistance('51.5074', '-0.1278', '51.5074', '-0.1278')
    assert.equal(dist, 0)
  })

  it('calculates distance between Sydney and Tokyo within 50 km tolerance', () => {
    // Sydney: -33.8688° S, 151.2093° E
    // Tokyo:   35.6762° N, 139.6503° E
    // Expected: ~7823 km
    const dist = geoDistance('-33.8688', '151.2093', '35.6762', '139.6503')
    assert.ok(
      Math.abs(dist - 7823) < 50,
      `Expected ~7823 km, got ${dist.toFixed(1)} km`
    )
  })
})

